code = sys.stdin.read()
import os
path = "/app/data/auto-opt/utils/llvm-85313/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp"
with open(path, "r") as f:
    text = f.read()

# Insert after icmp (A+B), A -> icmp B, 0
insert_after = r"""  if ((A == Op1 || B == Op1) && NoOp0WrapProblem)
    return new ICmpInst(Pred, A == Op1 ? B : A,
                        Constant::getNullValue(Op1->getType()));"""

new_code = r"""  if ((A == Op1 || B == Op1) && NoOp0WrapProblem)
    return new ICmpInst(Pred, A == Op1 ? B : A,
                        Constant::getNullValue(Op1->getType()));

  // X / C < X -> X > 0
  // X / C > X -> X < 0
  // X / C <= X -> X >= 0
  // X / C >= X -> X <= 0
  if (Op0->getType()->isIntOrIntVectorTy()) {
    Value *Num = nullptr, *Denom = nullptr;
    if (match(Op0, m_SDiv(m_Value(Num), m_Value(Denom))) && Num == Op1) {
      if (match(Denom, m_ConstantInt()) && !match(Denom, m_Zero()) && !match(Denom, m_One())) {
        if (Pred == ICmpInst::ICMP_SLT)
          return new ICmpInst(ICmpInst::ICMP_SGT, Op1, Constant::getNullValue(Op1->getType()));
        if (Pred == ICmpInst::ICMP_SGT)
          return new ICmpInst(ICmpInst::ICMP_SLT, Op1, Constant::getNullValue(Op1->getType()));
        if (Pred == ICmpInst::ICMP_SLE)
          return new ICmpInst(ICmpInst::ICMP_SGE, Op1, Constant::getNullValue(Op1->getType()));
        if (Pred == ICmpInst::ICMP_SGE)
          return new ICmpInst(ICmpInst::ICMP_SLE, Op1, Constant::getNullValue(Op1->getType()));
      }
    }
  }
"""

text = text.replace(insert_after, new_code)
with open(path, "w") as f:
    f.write(text)
EOF
python3 /tmp/apply_cmp.py"}

